# --- FLASK WEB ROUTES ---
@app.route('/')
def index():
    # Serves the HTML webpage
    return render_template('index.html', robot_map=robot_map)

@app.route('/calculate_path', methods=['POST'])
def calculate_path():
    data = request.json
    start = tuple(data['start'])
    goal = tuple(data['goal'])
    
    navigator = AutonomousNavigator(robot_map)
    path = navigator.find_path(start, goal)
    
    if path:
        print(f"Robot ordered to move. Waypoints: {path}")
        # Here is where we will eventually send the path to the ESP32!
        return jsonify({"status": "success", "path": path})
    else:
        return jsonify({"status": "error", "message": "No valid path found. Obstacles in the way!"})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)